# solarsentinel_kaggle.py

import os
import sys
import subprocess
import base64
import logging
import warnings

# Aggressive silence for the controller script
logging.disable(logging.INFO)
try:
    from absl import logging as absl_logging
    absl_logging.set_verbosity(absl_logging.ERROR)
except ImportError:
    pass
warnings.filterwarnings("ignore")

# Base64 encoded code to avoid escape character issues
SUBMISSION_B64 = """"""
TRAINER_B64 = """"""
BENCHMARK_B64 = """"""

def setup():
    print("Initializing SolarSentinel Training Environment...")
    os.makedirs("snapshots", exist_ok=True)
    
    with open("submission.py", "wb") as f:
        f.write(base64.b64decode(SUBMISSION_B64))
        
    with open("self_play_trainer.py", "wb") as f:
        f.write(base64.b64decode(TRAINER_B64))
        
    with open("benchmark.py", "wb") as f:
        f.write(base64.b64decode(BENCHMARK_B64))
        
    print("Installing/Upgrading dependencies...")
    # Update kaggle-environments to at least 1.28.0 to ensure orbit_wars is available
    subprocess.run([sys.executable, "-m", "pip", "install", "--upgrade", "kaggle-environments>=1.28.0", "numpy", "torch"], check=True)
    
    # Optional: Verify environment presence
    try:
        from kaggle_environments import make
        env = make("orbit_wars")
        print(f"Verified environment: {env.name} v{env.version}")
    except Exception as e:
        print(f"Warning during env verification: {e}")

def run():
    print("\n[PHASE 1] Parameter Evolution (30 Generations)...")
    # Using check=True carefully, but we want to see output if it fails
    subprocess.run([sys.executable, "self_play_trainer.py", "evolve", "--generations", "30", "--pop-size", "8", "--games-per-eval", "20"], check=True)
    
    print("\n[PHASE 2] Self-Play Arena (500 Games)...")
    subprocess.run([sys.executable, "self_play_trainer.py", "arena", "--games", "500", "--snapshot-every", "50"], check=True)

if __name__ == "__main__":
    setup()
    run()
